db:update.db:input-parameters:
#[{
  nivel: vars.nivel,
  descripcion: (vars.nivelEntrada.descripcion default "") as String
}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  data: {
    resource: "Nivel",
    operation: "UPDATED",
    id: vars.nivel,
    message: "Nivel actualizado correctamente.",
    timestamp: vars.timestampOperacion
  }
}

file:write.file:content:
#[%dw 2.0
output application/xml
---
OperationResultEnvelope: {
  data: {
    resource: "Nivel",
    operation: "UPDATED",
    id: vars.nivel,
    message: "Nivel actualizado correctamente.",
    timestamp: vars.timestampOperacion
  }
}]

