ee:message.ee:set-payload:
%dw 2.0
output application/json
var n = vars.nivelRows[0]
---
{
  data: {
    nivel: (n.nivel default 0) as Number,
    descripcion: (n.descripcion default "") as String
  }
}

file:write.file:content:
#[%dw 2.0
output application/xml
var n = vars.nivelRows[0]
---
NivelEnvelope: {
  data: {
    nivel: (n.nivel default 0) as Number,
    descripcion: (n.descripcion default "") as String
  }
}]

db:insert.db:input-parameters:
#[{
  nivel: (vars.nivelEntrada.nivel default 0) as Number,
  descripcion: (vars.nivelEntrada.descripcion default "") as String
}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	data: {
		nivel: (vars.nivelEntrada.nivel default 0) as Number,
		descripcion: (vars.nivelEntrada.descripcion default "") as String
	}
}

file:write.file:content:
#[%dw 2.0
output application/xml
---
NivelEnvelope: {
  data: {
    nivel: (vars.nivelEntrada.nivel default 0) as Number,
    descripcion: (vars.nivelEntrada.descripcion default "") as String
  }
}]
